ALTER TABLE "transactions" ADD FOREIGN KEY ("listing_id") REFERENCES "listings" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "transactions" ADD FOREIGN KEY ("buyer_user_id") REFERENCES "users" ("id") DEFERRABLE INITIALLY IMMEDIATE;

ALTER TABLE "transactions" ADD FOREIGN KEY ("seller_user_id") REFERENCES "users" ("id") DEFERRABLE INITIALLY IMMEDIATE;

